import { useEffect, useState } from "react";
import { GetFixtureGrid } from "../../services/fixture-service";
import { FixtureGrid } from "../../objects/fixture-grid";
import { GetTeams } from "../../services/teams-service";
import { Team } from "../../objects/team";

const FixtureGridComponent = (seasonId : string) =>
{
    const [fixtureGrid, setFixtureGrid] = useState<FixtureGrid[] | null>(null); 
    const [teams, setTeams] = useState<Team[] | null>(null); 
    
    useEffect(() => {
        GetTeams().then(teams => setTeams(teams));
        GetFixtureGrid(seasonId).then(fixtureGrid => setFixtureGrid(fixtureGrid));
    }, [seasonId])


    return(
        <div className="row">
            <table>
                <thead>
                    <tr>
                        <th>Team</th>
                        {
                            teams?.map(team => 
                            
                                <th>team.name</th>
                            )
                        }
                        <th></th>
                    </tr>
                </thead>
            </table>
        </div>
    )
}
export default FixtureGridComponent;
